import React from 'react';
import bg from '..';

function HomeHeader() {
    const headerStyle = {
        textAlign: 'center',
        padding: '40px 20px',
        backgroundImage: `url(${bg})`,
        backgroundSize: 'cover',
        backgroundPosition: 'center'
    };

    return (
        <header style={headerStyle}>
            <h1 style={{ fontSize: 32, marginBottom: 12 }}>Bienvenue sur CookBook</h1>
            <p style={{ fontSize: 18, color: '#555' }}>Découvrez des recettes délicieuses et faciles à préparer !</p>
        </header>
    );
}

export default HomeHeader;
